   219→/**
   220→ * Core routing decision logic
   221→ *
   222→ * Implements the three-threshold AI routing strategy:
   223→ * - High confidence (>= highThreshold): Skip AI - rule-based results are reliable
   224→ * - Low confidence (< lowThreshold): Skip AI - too uncertain for AI to help
   225→ * - Medium confidence (lowThreshold <= score < highThreshold):
   226→ *   - If score >= aiRequiredThreshold: Route to AI (worth the cost)
   227→ *   - Otherwise: Skip AI (below cost threshold)
   228→ *
   229→ * @param selectedLabels - Labels selected by multi-label selection stage
   230→ * @param candidateScores - All candidate category scores
   231→ * @param highConfidenceThreshold - Skip AI if score >= this (confident in rules)
   232→ * @param aiRequiredThreshold - Within medium range, route to AI if score >= this
   233→ * @param lowConfidenceThreshold - Skip AI if score < this (too uncertain)
   234→ * @param skipAiConditions - Additional conditions to skip AI (e.g., hardAssertion)
   235→ * @returns Routing decision with reasoning
   236→ */
   237→function makeRoutingDecision(
   238→  selectedLabels: SelectedLabel[],
   239→  candidateScores: Record<string, CandidateScore>,
   240→  highConfidenceThreshold: number,
   241→  aiRequiredThreshold: number,
   242→  lowConfidenceThreshold: number,
   243→  skipAiConditions: string[]
   244→): RoutingDecision {
   245→  // Case 1: No labels selected - route to AI for last chance classification
   246→  if (selectedLabels.length === 0) {
   247→    return {
   248→      routeToAi: true,
   249→      routingReason: 'No labels selected - AI classification may recover classification',
   250→      confidenceAssessment: 'noClassification',
   251→      costConsideration: 'recoveryAttempt',
   252→    };
   253→  }
   254→
   255→  // Case 2: Check for hard assertions (skip AI condition)
   256→  // Hard assertions are domain-based classifications that are authoritative
   257→  if (skipAiConditions.includes('hardAssertion')) {
   258→    const hasHardAssertion = Object.values(candidateScores).some((score) => score.hardAssertion);
   259→    if (hasHardAssertion) {
   260→      return {
   261→        routeToAi: false,
   262→        routingReason: 'hard assertion applied - domain-based classification is authoritative',
   263→        confidenceAssessment: 'hardAssertionSkip',
   264→        costConsideration: 'aiUnnecessary',
   265→      };
   266→    }
   267→  }
   268→
   269→  // Case 3: Analyze primary label confidence for threshold-based routing
   270→  const primaryLabel = selectedLabels.find((label) => label.isPrimary) || selectedLabels[0];
   271→  const primaryScore = primaryLabel.confidence;
   272→
   273→  // High confidence threshold check: score >= highThreshold → Skip AI
   274→  // Rule-based results are reliable at this confidence level
   275→  if (primaryScore >= highConfidenceThreshold) {
   276→    return {
   277→      routeToAi: false,
   278→      routingReason: `High confidence primary label ${primaryLabel.category} (score: ${primaryScore}) - rule-based results reliable`,
   279→      confidenceAssessment: 'highConfidence',
   280→      costConsideration: 'aiUnnecessary',
   281→    };
   282→  }
   283→
   284→  // Low confidence threshold check: score < lowThreshold → Skip AI
   285→  // Too uncertain for AI to provide meaningful improvement
   286→  if (primaryScore < lowConfidenceThreshold) {
   287→    return {
   288→      routeToAi: false,
   289→      routingReason: `Very low confidence primary label ${primaryLabel.category} (score: ${primaryScore}) - likely unclassifiable`,
   290→      confidenceAssessment: 'veryLowConfidence',
   291→      costConsideration: 'aiIneffective',
   292→    };
   293→  }
   294→
   295→  // Medium confidence range: lowThreshold <= score < highThreshold
   296→  // Analyze additional factors to determine if AI is worth the cost
   297→  const hasMultipleLabels = selectedLabels.length > 1;
   298→  const hasCloseCompetitors = checkCloseCompetitors(candidateScores, primaryScore, 3);
   299→
   300→  // Build routing reason with contextual factors
   301→  if (primaryScore >= lowConfidenceThreshold && primaryScore < highConfidenceThreshold) {
   302→    let aiRoutingReason = `Medium confidence primary label ${primaryLabel.category} (score: ${primaryScore})`;
   303→    let costConsideration = 'beneficialEnhancement';
   304→
   305→    // Additional factors that increase AI value
   306→    if (hasCloseCompetitors) {
   307→      aiRoutingReason += ' with close competing categories';
   308→      costConsideration = 'disambiguationValuable';
   309→    }
   310→
   311→    if (hasMultipleLabels) {
   312→      aiRoutingReason += ' with multiple labels selected';
   313→      costConsideration = 'multiLabelValidation';
   314→    }
   315→
   316→    // Apply aiRequiredThreshold: only route to AI if score is high enough
   317→    // This prevents routing low-medium confidence emails that won't benefit from AI
   318→    if (primaryScore >= aiRequiredThreshold) {
   319→      return {
   320→        routeToAi: true,
   321→        routingReason: aiRoutingReason + ' - AI classification can improve accuracy',
   322→        confidenceAssessment: 'mediumConfidence',
   323→        costConsideration: costConsideration,
   324→      };
   325→    } else {
   326→      return {
   327→        routeToAi: false,
   328→        routingReason: aiRoutingReason + ' but below AI routing threshold - accept rule-based result',
   329→        confidenceAssessment: 'lowMediumConfidence',
   330→        costConsideration: 'costThresholdNotMet',
   331→      };
   332→    }
   333→  }
   334→
   335→  // Default case (shouldn't reach here with proper threshold ordering: low < aiRequired < high)
   336→  return {
   337→    routeToAi: false,
   338→    routingReason: `Unclear confidence assessment (score: ${primaryScore}) - defaulting to rule-based results`,
   339→    confidenceAssessment: 'unclear',
   340→    costConsideration: 'defaultConservative',
   341→  };
   342→}
   343→
   344→/**
   345→ * Check if there are close competing categories that AI could help disambiguate
   346→ */
   347→function checkCloseCompetitors(
   348→  candidateScores: Record<string, CandidateScore>,
   349→  primaryScore: number,
   350→  competitorGap: number = 3
   351→): boolean {
   352→  const competitors = Object.entries(candidateScores)
   353→    .map(([categoryCode, scoreData]) => ({
   354→      category: categoryCode,
   355→      score: scoreData.score || 0,
   356→    }))
   357→    .filter((cat) => cat.score > 0 && cat.score < primaryScore)
   358→    .filter((cat) => primaryScore - cat.score <= competitorGap);
   359→
   360→  return competitors.length > 0;
   361→}
   362→
   363→/**
   364→ * Generate comprehensive explainability trace
   365→ */
   366→function generateExplainabilityTrace(
   367→  selectedLabels: SelectedLabel[],
   368→  candidateScores: Record<string, CandidateScore>,
   369→  routingDecision: RoutingDecision,
   370→  thresholds: {
   371→    highConfidenceThreshold: number;
   372→    aiRequiredThreshold: number;
   373→    lowConfidenceThreshold: number;
   374→  },
   375→  startTime: number
   376→): AIRoutingExplainabilityTrace {
   377→  const processingTime = Date.now() - startTime;
   378→  const primaryLabel = selectedLabels.find((l) => l.isPrimary) || selectedLabels[0];
   379→
   380→  return {
   381→    stageType: 'aiRouting',
   382→    stageOrder: 8,
   383→    decisionFactors: {
   384→      primaryScore: primaryLabel?.confidence || 0,
   385→      thresholdAnalysis: {
   386→        highConfidenceThreshold: thresholds.highConfidenceThreshold,
   387→        aiRequiredThreshold: thresholds.aiRequiredThreshold,
   388→        lowConfidenceThreshold: thresholds.lowConfidenceThreshold,
   389→        primaryScore: primaryLabel?.confidence || 0,
   390→        thresholdMet: primaryLabel?.confidence >= thresholds.aiRequiredThreshold ? 'aiRequired' : 'belowThreshold',
   391→      },
   392→      competitorAnalysis: {
   393→        closeCompetitorsFound: checkCloseCompetitors(candidateScores, primaryLabel?.confidence || 0),
   394→        competitorCount: Object.keys(candidateScores).length - 1,
   395→        multipleLabelsSelected: selectedLabels.length > 1,
   396→      },
   397→    },
   398→    reasoning: routingDecision.routingReason,
   399→    processingMetadata: {
   400→      processingTimeMs: processingTime,
   401→      inputLabelsCount: selectedLabels.length,
   402→      candidateScoresCount: Object.keys(candidateScores).length,
   403→    },
   404→  };
   405→}
